var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"아무리 견습이라고 해도 그렇지, 명색이 대마녀란 녀석이 이런 백지수표 같은 계약을 맺어?","JPN":"いくら見習いとは言え、大魔女ともなるヤツがこんなあやふやな契約を結んでどうする？","ENG":"I know you're still in training, but you're a Great Witch. I can't believe you've agreed to an unconditional contract like this.","TWN":"就算只是個見習的，名為大魔女的傢伙竟然要簽這種像空白支票的契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"솔라 코덱스의 명성에 먹칠을 하는구만. 에잉.","JPN":"ソーラーコーデックスの名折れだな、まったく。","ENG":"You've disgraced the Solar Codex, hmpf!","TWN":"實在是太侮辱太陽法典的名聲了，唉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"헤헤, 레일리라면 역시 잔소리 할 줄 알았어.","JPN":"へへ、やっぱりレイリーには小言を言われると思った。","ENG":"Hee hee. I knew you'd say that, Rayleigh.","TWN":"嘿嘿，我就知道瑞利會嘮叨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"할 줄 알았으면 안 하게 해야지!","JPN":"だったら言われないようにしろ！","ENG":"If you knew, you shouldn't have done it!","TWN":"知道我會嘮叨，那妳就別簽啊！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"하, 하지만 사장님은 믿을 수 있는 사람인걸......","JPN":"で、でも社長は信頼できる人だから……","ENG":"B-but the Boss is someone I can trust.","TWN":"但、但是，老闆是值得信賴的人啊……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"민트 초코로 만든 내 신 메뉴도 매번 시식해 주고 말이야.","JPN":"ミントチョコ味の私の新メニューも毎回試食してくれるし。","ENG":"Also, he doesn't mind trying my mint chocolate recipes every time I come up with them.","TWN":"每次都會試吃我用薄荷巧克力做的新菜單。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"그, 그걸 정말 먹어 준다고? 확실히 신뢰가 가는 사람이긴 하군......","JPN":"そ、それを本当に食べてくれるのか？それは確かに信頼できるかもな……","ENG":"H-he doesn't really mind that? He surely is a good boss...","TWN":"真、真的……敢吃那個？果真是個特別值得信賴的人……   "},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"앞으로 함께할 동료인데 사소한 데까지 마음이 통해야지. 안 그래?","JPN":"これから一緒にいる仲間なんだから、\\n些細なことまで気が合わないと。ね？","ENG":"We're going to be coworkers from now on. The more we share, the better. Don't you agree?","TWN":"既然是之後會在一起的夥伴，就連瑣碎的事情都要心意相通才對啊，不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"나 원. 메이 녀석이 정말 골치 아픈 짐을 떠맡기고 갔어.","JPN":"まったく、メイのヤツは本当に困った荷物を預けていったもんだ。","ENG":"Geez, May has left me with a burden.","TWN":"真是的，梅依那傢伙，真的把一個麻煩的東西託付給我了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"이렇게 얼빠진 애니까,\xA0자네가 꼭 좀 신경 써 주게.","JPN":"こんなだらしのないやつだが、是非ともよろしく頼む。","ENG":"She's a babe in the woods, as you can see. Please take good care of her.","TWN":"這麼傻氣的孩子，你一定要多擔待一點啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"혹시 정 마음에 안 들면 말만 하라고.\xA0이 녀석 대신 사장을 새로운 계약자로 만들어 줄 테니까.","JPN":"もしどうしても気に入らなかったら言ってくれ。こいつの代わりに、社長を新しい契約者にしてあげるからな。","ENG":"If you're not happy with her, you let me know. I'll let her go and enter into a contract with you at once.","TWN":"如果實在不滿意的話就跟我說，我會代替這傢伙跟老闆重新訂立新契約的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아,\xA0잠깐!\xA0레일리!\xA0그건 비겁해!\xA0사장님은 나랑 계약하기로 한 거라고!","JPN":"あっ、ちょっと！レイリー！それはずるい！社長と契約することにしたのは私なの！","ENG":"What? Rayleigh, you can't do that! The Boss is entering a contract with me, not you!","TWN":"啊，等等！瑞利！你太狡猾了！老闆是要跟我簽約耶！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};